const d = $input.first().json;
return (d.earningsCalendar || []).map(e => ({
  json: {
    ticker: e.symbol,
    report_date: e.date,
    fiscal_quarter: 'Q' + (e.quarter || ''),
    eps_estimate: e.epsEstimate != null ? e.epsEstimate : null,
    eps_actual: e.epsActual != null ? e.epsActual : null,
    revenue_estimate: e.revenueEstimate != null ? e.revenueEstimate : null,
    revenue_actual: e.revenueActual != null ? e.revenueActual : null,
    surprise_percent: e.surprisePercent != null ? e.surprisePercent : null
  }
}));

// FMP returns an array — each item arrives as a separate input item
const items = $input.all();
return items.map(item => {
  const x = item.json;
  return {
    json: {
      ticker: x.symbol,
      ex_date: x.date,
      payment_date: x.paymentDate || null,
      record_date: x.recordDate || null,
      declaration_date: x.declarationDate || null,
      amount: x.dividend != null ? x.dividend : (x.adjDividend != null ? x.adjDividend : null),
      frequency: x.frequency || null
    }
  };
});
